import * as React from 'react';
import { render, act } from '@testing-library/react';

import { GlobalStoreFieldE } from 'Shared/types/GlobalStoreFieldE';
import { globalStore } from 'Shared/store/globalStore';
import { useGlobalValue } from 'Shared/store/useGlobalValue';

const TestComponent = () => {
  const value = useGlobalValue(GlobalStoreFieldE.AUTH_TOKEN);

  return <div data-testid="value">{value ?? 'null'}</div>;
};

describe('useGlobalValue', () => {
  beforeEach(() => {
    globalStore[GlobalStoreFieldE.AUTH_TOKEN].value = null;
  });

  it('returns current value from globalStore', () => {
    globalStore[GlobalStoreFieldE.AUTH_TOKEN].value = 'initial';

    const { getByTestId } = render(<TestComponent />);

    expect(getByTestId('value').textContent).toBe('initial');
  });

  it('updates when globalStore value changes', () => {
    const { getByTestId } = render(<TestComponent />);

    expect(getByTestId('value').textContent).toBe('null');

    act(() => {
      globalStore[GlobalStoreFieldE.AUTH_TOKEN].value = 'next';
    });

    expect(getByTestId('value').textContent).toBe('next');
  });
});

