import { renderHook } from '@testing-library/react';
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { useSwipeGesture } from './useSwipeGesture';

describe('useSwipeGesture', () => {
  let mockElement: HTMLDivElement;
  let onSwipeDownMock: ReturnType<typeof vi.fn>;

  beforeEach(() => {
    mockElement = document.createElement('div');
    onSwipeDownMock = vi.fn();
  });

  it('should return a ref object', () => {
    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: onSwipeDownMock,
      }),
    );

    expect(result.current.ref).toBeDefined();
    expect(result.current.ref.current).toBeNull();
  });

  it('should not add event listeners when enabled is false', () => {
    const addEventListenerSpy = vi.spyOn(mockElement, 'addEventListener');

    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: onSwipeDownMock,
        enabled: false,
      }),
    );

    result.current.ref.current = mockElement;

    expect(addEventListenerSpy).not.toHaveBeenCalled();
  });

  it('should add event listeners when enabled is true', () => {
    const addEventListenerSpy = vi.spyOn(mockElement, 'addEventListener');

    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: onSwipeDownMock,
        enabled: true,
      }),
    );

    result.current.ref.current = mockElement;

    // Force useEffect to run
    const { rerender } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: onSwipeDownMock,
        enabled: true,
      }),
    );

    result.current.ref.current = mockElement;
    rerender();

    expect(addEventListenerSpy).toHaveBeenCalledWith(
      'touchstart',
      expect.any(Function),
      { passive: false },
    );
    expect(addEventListenerSpy).toHaveBeenCalledWith(
      'touchmove',
      expect.any(Function),
      { passive: false },
    );
    expect(addEventListenerSpy).toHaveBeenCalledWith(
      'touchend',
      expect.any(Function),
    );
  });

  it('should call onSwipeDown when swipe exceeds threshold', () => {
    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: onSwipeDownMock,
        threshold: 100,
        enabled: true,
      }),
    );

    result.current.ref.current = mockElement;

    // Simulate touch events
    const touchStart = new TouchEvent('touchstart', {
      touches: [{ clientY: 100 } as Touch],
    });

    const touchEnd = new TouchEvent('touchend', {
      changedTouches: [{ clientY: 250 } as Touch],
    });

    mockElement.dispatchEvent(touchStart);
    mockElement.dispatchEvent(touchEnd);

    expect(onSwipeDownMock).toHaveBeenCalled();
  });

  it('should not call onSwipeDown when swipe is below threshold', () => {
    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: onSwipeDownMock,
        threshold: 100,
        enabled: true,
      }),
    );

    result.current.ref.current = mockElement;

    // Simulate touch events
    const touchStart = new TouchEvent('touchstart', {
      touches: [{ clientY: 100 } as Touch],
    });

    const touchEnd = new TouchEvent('touchend', {
      changedTouches: [{ clientY: 150 } as Touch],
    });

    mockElement.dispatchEvent(touchStart);
    mockElement.dispatchEvent(touchEnd);

    expect(onSwipeDownMock).not.toHaveBeenCalled();
  });

  it('should apply transform during swipe down', () => {
    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: onSwipeDownMock,
        enabled: true,
      }),
    );

    result.current.ref.current = mockElement;

    const touchStart = new TouchEvent('touchstart', {
      touches: [{ clientY: 100 } as Touch],
    });

    const touchMove = new TouchEvent('touchmove', {
      touches: [{ clientY: 150 } as Touch],
    });

    mockElement.dispatchEvent(touchStart);
    mockElement.dispatchEvent(touchMove);

    expect(mockElement.style.transform).toBe('translateY(50px)');
    expect(mockElement.style.transition).toBe('none');
  });

  it('should not apply transform during swipe up', () => {
    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: onSwipeDownMock,
        enabled: true,
      }),
    );

    result.current.ref.current = mockElement;

    const touchStart = new TouchEvent('touchstart', {
      touches: [{ clientY: 150 } as Touch],
    });

    const touchMove = new TouchEvent('touchmove', {
      touches: [{ clientY: 100 } as Touch],
    });

    mockElement.dispatchEvent(touchStart);
    mockElement.dispatchEvent(touchMove);

    expect(mockElement.style.transform).toBe('');
  });

  it('should reset styles on touch end', () => {
    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: onSwipeDownMock,
        threshold: 200,
        enabled: true,
      }),
    );

    result.current.ref.current = mockElement;

    const touchStart = new TouchEvent('touchstart', {
      touches: [{ clientY: 100 } as Touch],
    });

    const touchMove = new TouchEvent('touchmove', {
      touches: [{ clientY: 150 } as Touch],
    });

    const touchEnd = new TouchEvent('touchend', {
      changedTouches: [{ clientY: 150 } as Touch],
    });

    mockElement.dispatchEvent(touchStart);
    mockElement.dispatchEvent(touchMove);
    mockElement.dispatchEvent(touchEnd);

    expect(mockElement.style.transform).toBe('');
    expect(mockElement.style.transition).toBe('');
  });

  it('should use default threshold of 100px', () => {
    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: onSwipeDownMock,
        enabled: true,
      }),
    );

    result.current.ref.current = mockElement;

    const touchStart = new TouchEvent('touchstart', {
      touches: [{ clientY: 100 } as Touch],
    });

    const touchEnd = new TouchEvent('touchend', {
      changedTouches: [{ clientY: 200 } as Touch],
    });

    mockElement.dispatchEvent(touchStart);
    mockElement.dispatchEvent(touchEnd);

    expect(onSwipeDownMock).toHaveBeenCalled();
  });

  it('should clean up event listeners on unmount', () => {
    const removeEventListenerSpy = vi.spyOn(mockElement, 'removeEventListener');

    const { result, unmount } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: onSwipeDownMock,
        enabled: true,
      }),
    );

    result.current.ref.current = mockElement;

    unmount();

    expect(removeEventListenerSpy).toHaveBeenCalledWith(
      'touchstart',
      expect.any(Function),
    );
    expect(removeEventListenerSpy).toHaveBeenCalledWith(
      'touchmove',
      expect.any(Function),
    );
    expect(removeEventListenerSpy).toHaveBeenCalledWith(
      'touchend',
      expect.any(Function),
    );
  });

  it('should handle missing touch in touchstart', () => {
    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: onSwipeDownMock,
        enabled: true,
      }),
    );

    result.current.ref.current = mockElement;

    const touchStart = new TouchEvent('touchstart', {
      touches: [] as unknown as TouchList,
    });

    expect(() => {
      mockElement.dispatchEvent(touchStart);
    }).not.toThrow();
  });

  it('should handle missing touch in touchmove', () => {
    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: onSwipeDownMock,
        enabled: true,
      }),
    );

    result.current.ref.current = mockElement;

    const touchStart = new TouchEvent('touchstart', {
      touches: [{ clientY: 100 } as Touch],
    });

    const touchMove = new TouchEvent('touchmove', {
      touches: [] as unknown as TouchList,
    });

    mockElement.dispatchEvent(touchStart);

    expect(() => {
      mockElement.dispatchEvent(touchMove);
    }).not.toThrow();
  });

  it('should handle missing touch in touchend', () => {
    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: onSwipeDownMock,
        enabled: true,
      }),
    );

    result.current.ref.current = mockElement;

    const touchStart = new TouchEvent('touchstart', {
      touches: [{ clientY: 100 } as Touch],
    });

    const touchEnd = new TouchEvent('touchend', {
      changedTouches: [] as unknown as TouchList,
    });

    mockElement.dispatchEvent(touchStart);

    expect(() => {
      mockElement.dispatchEvent(touchEnd);
    }).not.toThrow();
  });
});

