    expect(removeEventListenerSpy).toHaveBeenCalledWith(
      'touchstart',
      expect.any(Function),
    );
    expect(removeEventListenerSpy).toHaveBeenCalledWith(
      'touchmove',
      expect.any(Function),
    );
    expect(removeEventListenerSpy).toHaveBeenCalledWith(
      'touchend',
      expect.any(Function),
    );
  });

  it('should handle missing touch in touchstart', () => {
    const mockElement = document.createElement('div');

    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: onSwipeDownMock,
        enabled: true,
      }),
    );

